private bool IsNumeric(string s)
{
   double d;
   return double.TryParse(s, out d);
}

private void SearchAppliance(string filterText)
{
   var filteredItems = Appliances.Where(appliance =>
       appliance.Name.Contains(filterText, StringComparison.OrdinalIgnoreCase)
   );

   dataGridView1.DataSource(filteredItems.ToList());
}
```

##### Sorting

